// Normalise the VAPI end-of-call-report payload.
// VAPI wraps the actual event under .message in modern versions.
const payload = $input.first().json;
const body    = payload.body || payload;
const message = body.message || body;

const callId       = message.call?.id
                  || message.callId
                  || message.id
                  || `unknown-${Date.now()}`;
const assistantId  = message.assistant?.id
                  || message.assistantId
                  || message.call?.assistantId
                  || 'unknown';
const transcript   = message.transcript
                  || message.artifact?.transcript
                  || '';
const summary      = message.summary
                  || message.analysis?.summary
                  || '';
const duration     = Number(message.durationSeconds
                  || message.call?.duration
                  || message.artifact?.callDuration
                  || 0);
const endedReason  = message.endedReason || message.call?.endedReason || '';

// Tool calls live either at top level or scattered through artifact.messages.
let toolCalls = message.toolCalls || message.artifact?.toolCalls || [];
if (!toolCalls.length && Array.isArray(message.artifact?.messages)) {
  toolCalls = message.artifact.messages
    .filter(m => Array.isArray(m.toolCalls) && m.toolCalls.length)
    .flatMap(m => m.toolCalls);
}

return [{
  json: {
    call_id:     callId,
    assistant_id: assistantId,
    transcript,
    summary,
    duration,
    ended_reason: endedReason,
    tool_calls:  toolCalls,
    success_evaluation: message.analysis?.successEvaluation ?? null,
    raw_payload: message
  }
}];

// Parse JSON out of the Anthropic response and merge with upstream call data.
const resp     = $json;
const upstream = $('Extract Call Data').first().json;

const raw = resp?.content?.[0]?.text || '';
let analysis = {};
try {
  // Strip code fences if the model added them, then grab the outermost {...}.
  const cleaned = raw.replace(/```(?:json)?/g, '').trim();
  const match   = cleaned.match(/\{[\s\S]*\}/);
  analysis      = match ? JSON.parse(match[0]) : {};
} catch (e) {
  analysis = { errors: [], success_score: null, parse_error: e.message, raw };
}

const errors = Array.isArray(analysis.errors) ? analysis.errors : [];
const score  = typeof analysis.success_score === 'number' ? analysis.success_score : null;

const hasHigh   = errors.some(e => ['critical','high'].includes(String(e.severity || '').toLowerCase()));
const lowScore  = score !== null && score < 0.5;
const many      = errors.length >= 2;
const isCritical = hasHigh || lowScore;
const shouldOptimize = isCritical || many;

return [{
  json: {
    ...upstream,
    detected_errors:   errors,
    success_score:     score,
    is_critical:       isCritical,
    should_optimize:   shouldOptimize,
    analysis_summary:  analysis.summary || null,
    full_analysis:     analysis
  }
}];

// Stage the row that will be inserted into vapi_call_logs.
const d = $json;
return [{
  json: {
    ...d,
    call_log_row: {
      call_id:           d.call_id,
      assistant_id:      d.assistant_id,
      transcript:        d.transcript,
      summary:           d.summary,
      duration:          d.duration,
      ended_reason:      d.ended_reason,
      tool_calls:        d.tool_calls,
      success_score:     d.success_score,
      detected_errors:   d.detected_errors,
      is_critical:       d.is_critical,
      analysis_summary:  d.analysis_summary,
      raw_payload:       d.raw_payload
    }
  }
}];

// Build the body for the Optimizer LLM.
const assistant = $json;
const call      = $('Parse Analysis').item.json;

const messages   = assistant?.model?.messages || [];
const sysMsg     = messages.find(m => (m.role || '').toLowerCase() === 'system');
const oldPrompt  = sysMsg?.content || '';

const systemPrompt = [
  'You are a senior prompt engineer for production voice assistants.',
  'Given the current VAPI system prompt and the recent user friction/errors, rewrite the system prompt to explicitly prevent these specific errors from happening again.',
  '',
  'Hard rules:',
  '1. Preserve every existing capability, language section, pricing table and zone rule unless an error directly demands a change.',
  '2. Make changes minimal, additive and surgical — do NOT rewrite the whole prompt.',
  '3. Add explicit FORBIDDEN/CORRECT example pairs for each error type so the LLM has concrete patterns to avoid.',
  '4. Never change tool definitions, voice IDs or model parameters.',
  '5. Keep the language and tone consistent with the original (FR/NL/EN/TR sections must remain in their language).',
  '',
  'Return STRICT JSON only — no prose, no markdown fences. Schema:',
  '{',
  '  "new_prompt": "<full rewritten system prompt, ready to ship>",',
  '  "change_summary": "<2-4 bullets describing what you changed and why>",',
  '  "diff_targets": ["<short tag for each error addressed>"]',
  '}'
].join('\n');

const userMessage = [
  '## CURRENT SYSTEM PROMPT',
  '```',
  oldPrompt,
  '```',
  '',
  '## DETECTED ERRORS (from this call)',
  JSON.stringify(call.detected_errors || [], null, 2),
  '',
  '## ANALYSIS SUMMARY',
  call.analysis_summary || '(none)',
  '',
  '## TRANSCRIPT EXCERPT (last 2000 chars)',
  String(call.transcript || '').slice(-2000),
  '',
  'Rewrite the system prompt to prevent these errors. Return JSON only.'
].join('\n');

return [{
  json: {
    assistant_id:   call.assistant_id,
    call_id:        call.call_id,
    old_prompt:     oldPrompt,
    detected_errors: call.detected_errors,
    optimizer_body: {
      model:      'claude-opus-4-7',
      max_tokens: 8192,
      system:     systemPrompt,
      messages:   [ { role: 'user', content: userMessage } ]
    }
  }
}];

// Parse the optimizer output and prepare the prompt-history row.
const crypto   = require('crypto');
const resp     = $json;
const ctx      = $('Build Optimizer Body').item.json;

const raw = resp?.content?.[0]?.text || '';
let result = {};
try {
  const cleaned = raw.replace(/```(?:json)?/g, '').trim();
  const match   = cleaned.match(/\{[\s\S]*\}/);
  result        = match ? JSON.parse(match[0]) : {};
} catch (e) {
  result = { new_prompt: null, change_summary: null, parse_error: e.message, raw };
}

if (!result.new_prompt || result.new_prompt.length < 200) {
  // Fail soft — surface error to admin instead of breaking the workflow.
  result.parse_error = result.parse_error
    || 'Optimizer returned an empty or implausibly short prompt.';
}

const token = crypto.randomUUID();

return [{
  json: {
    ...ctx,
    new_prompt:        result.new_prompt || '',
    change_summary:    result.change_summary || '(no summary returned)',
    diff_targets:      result.diff_targets || [],
    parse_error:       result.parse_error || null,
    approval_token:    token,
    history_row: {
      assistant_id:        ctx.assistant_id,
      old_prompt:          ctx.old_prompt,
      new_prompt:          result.new_prompt || '',
      reason_for_update:   result.change_summary || 'auto-generated optimization',
      detected_errors:     ctx.detected_errors,
      triggering_call_id:  ctx.call_id,
      approval_token:      token,
      status:              'pending'
    }
  }
}];

// Compose the WhatsApp text for the admin and the Evolution API body.
const d           = $('Parse Optimizer').item.json;
const baseUrl     = $env.PUBLIC_N8N_BASE_URL || 'https://n8n.k-sat.tech';
const approveUrl  = `${baseUrl}/webhook/vapi-self-healing-approve?token=${encodeURIComponent(d.approval_token)}&action=approve`;
const rejectUrl   = `${baseUrl}/webhook/vapi-self-healing-approve?token=${encodeURIComponent(d.approval_token)}&action=reject`;

const errorsTxt = (d.detected_errors || [])
  .slice(0, 6)
  .map((e, i) => `${i + 1}. [${(e.severity || '?').toUpperCase()}] ${e.type || '?'}: ${e.description || ''}`)
  .join('\n');

const diffSize = (d.new_prompt || '').length - (d.old_prompt || '').length;

const text = [
  '🛠️ *VAPI Auto-Optimizer*',
  '',
  `Assistant: \`${d.assistant_id}\``,
  `Call: \`${d.call_id}\``,
  `Prompt size: ${d.old_prompt?.length || 0} → ${d.new_prompt?.length || 0} chars (${diffSize >= 0 ? '+' : ''}${diffSize})`,
  '',
  '*Errors detected:*',
  errorsTxt || '_(none parsed)_',
  '',
  '*Proposed change:*',
  String(d.change_summary || '').slice(0, 800),
  '',
  d.parse_error ? `⚠️ Parser warning: ${d.parse_error}` : '',
  '',
  `✅ APPROVE: ${approveUrl}`,
  `❌ REJECT:  ${rejectUrl}`
].filter(Boolean).join('\n');

return [{
  json: {
    ...d,
    evolution_body: {
      number: $env.ADMIN_WHATSAPP_NUMBER,
      text
    }
  }
}];

// Pull token + action from the query string and validate shape.
const q      = $json.query || {};
const token  = String(q.token  || '').trim();
const action = String(q.action || '').trim().toLowerCase();

if (!token) {
  throw new Error('Missing token');
}
if (!['approve', 'reject'].includes(action)) {
  throw new Error(`Invalid action: ${action}`);
}

return [{ json: { approval_token: token, action } }];

// Decide branch: approve | reject | already_handled | not_found.
const rows   = Array.isArray($json) ? $json : ($json.body || []);
const row    = rows[0];
const action = $('Validate Approval Input').item.json.action;

if (!row) {
  return [{ json: { branch: 'not_found', action } }];
}
if (row.status !== 'pending') {
  return [{ json: { branch: 'already_handled', action, history: row } }];
}
return [{
  json: {
    branch: action,
    action,
    history: row,
    approval_token: row.approval_token
  }
}];

// Build the PATCH body — preserve provider/model/temperature, replace only the system message.
const assistant   = $json;
const hist        = $('Resolve Branch').item.json.history;

const oldModel    = assistant.model || {};
const oldMessages = Array.isArray(oldModel.messages) ? oldModel.messages : [];

// Replace (or insert) the single system message; leave any other messages intact.
const newMessages = oldMessages.some(m => (m.role || '').toLowerCase() === 'system')
  ? oldMessages.map(m =>
      (m.role || '').toLowerCase() === 'system'
        ? { ...m, content: hist.new_prompt }
        : m)
  : [{ role: 'system', content: hist.new_prompt }, ...oldMessages];

return [{
  json: {
    history_id:    hist.id,
    assistant_id:  hist.assistant_id,
    patch_body:    {
      model: { ...oldModel, messages: newMessages }
    }
  }
}];
